namespace UniversityCourseCatalog.Models;

public class Department
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public string Id { get; set; } = "";
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string DepartmentId { get; set; } = "";
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public string CourseId { get; set; } = "";
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = "math", Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns." },
            new() { Id = "eng", Name = "English", Description = "Study of literature, writing, and critical analysis of texts." },
            new() { Id = "phys", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces of nature." },
            new() { Id = "hist", Name = "History", Description = "Examination of past events and their impact on the modern world." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new()
            {
                Id = "cs101", Code = "CS 101", Title = "Introduction to Computer Science",
                Description = "A broad introduction to computer science covering fundamental concepts including abstraction, algorithms, data structures, and web development.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = "cs", IsFeatured = true,
                Instructor = new() { Name = "Dr. Sarah Chen", Title = "Associate Professor", Bio = "Dr. Chen specializes in CS education and has published extensively on introductory programming pedagogy.", Email = "schen@lakewood.edu" }
            },
            new()
            {
                Id = "cs201", Code = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures such as arrays, linked lists, trees, and graphs, along with algorithm design and analysis techniques.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = "cs",
                Instructor = new() { Name = "Dr. James Rivera", Title = "Professor", Bio = "Dr. Rivera has over 20 years of experience in algorithm research and competitive programming.", Email = "jrivera@lakewood.edu" }
            },
            new()
            {
                Id = "cs310", Code = "CS 310", Title = "Artificial Intelligence",
                Description = "Introduction to AI concepts including search, knowledge representation, machine learning, and natural language processing.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = "cs", IsFeatured = true,
                Instructor = new() { Name = "Dr. Priya Patel", Title = "Assistant Professor", Bio = "Dr. Patel's research focuses on deep learning and computer vision applications in healthcare.", Email = "ppatel@lakewood.edu" }
            },

            // Mathematics
            new()
            {
                Id = "math101", Code = "MATH 101", Title = "Calculus I",
                Description = "Introduction to limits, derivatives, and integrals of single-variable functions with applications to science and engineering.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = "math",
                Instructor = new() { Name = "Dr. Robert Klein", Title = "Professor", Bio = "Dr. Klein is an award-winning educator known for making calculus accessible and engaging.", Email = "rklein@lakewood.edu" }
            },
            new()
            {
                Id = "math201", Code = "MATH 201", Title = "Linear Algebra",
                Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and their applications.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = "math", IsFeatured = true,
                Instructor = new() { Name = "Dr. Maria Gonzalez", Title = "Associate Professor", Bio = "Dr. Gonzalez researches applications of linear algebra in data science and quantum computing.", Email = "mgonzalez@lakewood.edu" }
            },
            new()
            {
                Id = "math305", Code = "MATH 305", Title = "Probability and Statistics",
                Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis.",
                Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = "math",
                Instructor = new() { Name = "Dr. Alan Whitfield", Title = "Professor", Bio = "Dr. Whitfield has consulted for major tech companies on statistical modeling and data analysis.", Email = "awhitfield@lakewood.edu" }
            },

            // English
            new()
            {
                Id = "eng101", Code = "ENG 101", Title = "College Writing",
                Description = "Development of critical reading, thinking, and writing skills through analysis of diverse texts and composing academic essays.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = "eng",
                Instructor = new() { Name = "Prof. Diana Morris", Title = "Senior Lecturer", Bio = "Prof. Morris has authored two composition textbooks and leads the university writing center.", Email = "dmorris@lakewood.edu" }
            },
            new()
            {
                Id = "eng210", Code = "ENG 210", Title = "American Literature",
                Description = "Survey of American literary works from the colonial period through the 21st century, examining themes of identity, freedom, and democracy.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = "eng",
                Instructor = new() { Name = "Dr. Thomas Reed", Title = "Associate Professor", Bio = "Dr. Reed is a specialist in 20th-century American fiction and has published a book on the Harlem Renaissance.", Email = "treed@lakewood.edu" }
            },
            new()
            {
                Id = "eng315", Code = "ENG 315", Title = "Creative Writing Workshop",
                Description = "Workshop-based course focusing on writing and revising original fiction and poetry, with peer critique sessions.",
                Credits = 3, Schedule = "Wed 3:00–5:50 PM", DepartmentId = "eng", IsFeatured = true,
                Instructor = new() { Name = "Prof. Lena Park", Title = "Visiting Writer", Bio = "Prof. Park is a published novelist and poet whose work has appeared in The New Yorker and Poetry Magazine.", Email = "lpark@lakewood.edu" }
            },

            // Physics
            new()
            {
                Id = "phys101", Code = "PHYS 101", Title = "General Physics I",
                Description = "Introduction to classical mechanics covering kinematics, Newton's laws, energy, momentum, and rotational motion.",
                Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:50 PM", DepartmentId = "phys",
                Instructor = new() { Name = "Dr. Michael Torres", Title = "Professor", Bio = "Dr. Torres is a former NASA researcher who brings real-world physics applications into the classroom.", Email = "mtorres@lakewood.edu" }
            },
            new()
            {
                Id = "phys201", Code = "PHYS 201", Title = "Electromagnetism",
                Description = "Study of electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM + Lab Fri 2:00–4:50 PM", DepartmentId = "phys",
                Instructor = new() { Name = "Dr. Karen Liu", Title = "Associate Professor", Bio = "Dr. Liu's research in photonics has been funded by the National Science Foundation.", Email = "kliu@lakewood.edu" }
            },
            new()
            {
                Id = "phys310", Code = "PHYS 310", Title = "Quantum Mechanics",
                Description = "Introduction to quantum theory including wave-particle duality, the Schrödinger equation, and applications to atomic physics.",
                Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = "phys", IsFeatured = true,
                Instructor = new() { Name = "Dr. Erik Johansson", Title = "Professor", Bio = "Dr. Johansson is an internationally recognized researcher in quantum information theory.", Email = "ejohansson@lakewood.edu" }
            },

            // History
            new()
            {
                Id = "hist101", Code = "HIST 101", Title = "World Civilizations I",
                Description = "Survey of major world civilizations from antiquity through the Renaissance, exploring political, social, and cultural developments.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = "hist",
                Instructor = new() { Name = "Dr. Angela Foster", Title = "Professor", Bio = "Dr. Foster is a specialist in ancient Mediterranean cultures and has led archaeological digs in Greece.", Email = "afoster@lakewood.edu" }
            },
            new()
            {
                Id = "hist220", Code = "HIST 220", Title = "The American Civil War",
                Description = "In-depth study of the causes, conduct, and consequences of the American Civil War and Reconstruction era.",
                Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = "hist",
                Instructor = new() { Name = "Dr. William Hayes", Title = "Associate Professor", Bio = "Dr. Hayes has authored multiple books on 19th-century American military and political history.", Email = "whayes@lakewood.edu" }
            },
            new()
            {
                Id = "hist340", Code = "HIST 340", Title = "Modern East Asia",
                Description = "Examination of the political, economic, and cultural transformations in China, Japan, and Korea from the 19th century to the present.",
                Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", DepartmentId = "hist",
                Instructor = new() { Name = "Dr. Yuki Tanaka", Title = "Assistant Professor", Bio = "Dr. Tanaka specializes in modern Japanese history and transnational cultural exchanges in East Asia.", Email = "ytanaka@lakewood.edu" }
            }
        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments.AsReadOnly();

    public Department? GetDepartment(string id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? departmentId = null, string? searchTerm = null)
    {
        IEnumerable<Course> results = _courses;

        if (!string.IsNullOrWhiteSpace(departmentId))
            results = results.Where(c => c.DepartmentId == departmentId);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLowerInvariant();
            results = results.Where(c =>
                c.Title.ToLowerInvariant().Contains(term) ||
                c.Code.ToLowerInvariant().Contains(term) ||
                c.Description.ToLowerInvariant().Contains(term));
        }

        return results.ToList().AsReadOnly();
    }

    public Course? GetCourse(string id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList().AsReadOnly();

    public void SubmitEnrollmentRequest(EnrollmentRequest request) => _enrollmentRequests.Add(request);
}

