arguments.file_text:
@page "/courses"
@page "/courses/{departmentId}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services

@inject CatalogService CatalogService

<PageTitle>Courses - Lakewood University</PageTitle>

<div class="container mt-4">
    <h1>Course Catalog</h1>

    @{
        var currentDept = !string.IsNullOrEmpty(DepartmentId) ? CatalogService.GetDepartment(DepartmentId) : null;
    }
    @if (currentDept != null)
    {
        <h4 class="text-muted">@currentDept.Name</h4>
    }

    <form method="get" action="/courses" class="row g-3 my-4">
        <div class="col-md-5">
            <input type="text" name="search" class="form-control" placeholder="Search courses..." value="@Search" />
        </div>
        <div class="col-md-4">
            <select name="dept" class="form-select" onchange="this.form.action='/courses/' + this.value; this.form.submit();">
                <option value="">All Departments</option>
                @foreach (var dept in CatalogService.GetDepartments())
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <button type="submit" class="btn btn-primary w-100">Search</button>
        </div>
    </form>

    @{
        var courses = CatalogService.GetCourses(DepartmentId, Search);
        var departments = CatalogService.GetDepartments();
    }

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in courses)
                    {
                        var deptName = departments.FirstOrDefault(d => d.Id == course.DepartmentId)?.Name ?? "";
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@deptName</td>
                            <td>@course.Credits</td>
                            <td>@course.Schedule</td>
                            <td><a href="/courses/detail/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    <a href="/courses" class="btn btn-secondary mt-3">Clear Filters</a>
</div>

@code {
    [Parameter]
    public string? DepartmentId { get; set; }

    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }
}

@page "/courses/detail/{courseId}"
@using UniversityCourseCatalog.Services

@inject CatalogService CatalogService

<PageTitle>Course Detail - Lakewood University</PageTitle>

<div class="container mt-4">
    @{
        var course = CatalogService.GetCourse(CourseId ?? "");
    }

    @if (course == null)
    {
        <div class="alert alert-warning">Course not found.</div>
        <a href="/courses" class="btn btn-secondary">Back to Courses</a>
    }
    else
    {
        var dept = CatalogService.GetDepartment(course.DepartmentId);

        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
                @if (dept != null)
                {
                    <li class="breadcrumb-item"><a href="/courses/@dept.Id">@dept.Name</a></li>
                }
                <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
            </ol>
        </nav>

        <div class="row">
            <div class="col-lg-8">
                <h1>@course.Code — @course.Title</h1>
                @if (course.IsFeatured)
                {
                    <span class="badge featured-badge mb-3">Featured</span>
                }
                <p class="lead">@course.Description</p>

                <div class="row mt-4">
                    <div class="col-sm-6">
                        <h5>Credits</h5>
                        <p>@course.Credits</p>
                    </div>
                    <div class="col-sm-6">
                        <h5>Schedule</h5>
                        <p>@course.Schedule</p>
                    </div>
                </div>
            </div>

            <div class="col-lg-4">
                <div class="card course-card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6>@course.Instructor.Name</h6>
                        <p class="text-muted mb-1">@course.Instructor.Title</p>
                        <p>@course.Instructor.Bio</p>
                        <p><a href="mailto:@course.Instructor.Email">@course.Instructor.Email</a></p>
                    </div>
                </div>
            </div>
        </div>

        <div class="mt-4">
            <a href="/courses" class="btn btn-secondary me-2">Back to Courses</a>
            <a href="/enroll?courseId=@course.Id" class="btn btn-primary">Enroll in This Course</a>
        </div>
    }
</div>

@code {
    [Parameter]
    public string? CourseId { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services

@inject CatalogService CatalogService

<PageTitle>Enroll - Lakewood University</PageTitle>

<div class="container mt-4">
    <h1>Course Enrollment</h1>

    @if (_submitted)
    {
        <div class="alert alert-success mt-4">
            <h4 class="alert-heading">Enrollment Request Submitted!</h4>
            <p>Thank you, <strong>@Enrollment.StudentName</strong>. Your enrollment request for
                <strong>@(CatalogService.GetCourse(Enrollment.CourseId)?.Title ?? "the selected course")</strong>
                has been received.</p>
            <hr>
            <p class="mb-0"><a href="/courses" class="alert-link">Browse more courses</a> or <a href="/enroll" class="alert-link">submit another enrollment</a>.</p>
        </div>
    }
    else
    {
        <p class="text-muted">Fill out the form below to request enrollment in a course.</p>

        <form method="post" @formname="enrollment" class="mt-4" style="max-width: 600px;">
            <AntiforgeryToken />

            <div class="mb-3">
                <label for="studentName" class="form-label">Student Name</label>
                <input type="text" class="form-control" id="studentName" name="Enrollment.StudentName"
                       value="@Enrollment.StudentName" required />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <input type="text" class="form-control" id="studentId" name="Enrollment.StudentId"
                       value="@Enrollment.StudentId" required />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <select class="form-select" id="courseId" name="Enrollment.CourseId" required>
                    <option value="">-- Select a Course --</option>
                    @foreach (var course in CatalogService.GetCourses())
                    {
                        <option value="@course.Id" selected="@(course.Id == _effectiveCourseId)">@course.Code — @course.Title</option>
                    }
                </select>
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment</button>
            <a href="/courses" class="btn btn-secondary ms-2">Cancel</a>
        </form>
    }
</div>

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Enrollment { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public string? PreselectedCourseId { get; set; }

    private bool _submitted;
    private string _effectiveCourseId = "";

    protected override void OnInitialized()
    {
        _effectiveCourseId = Enrollment.CourseId;
        if (string.IsNullOrEmpty(_effectiveCourseId) && !string.IsNullOrEmpty(PreselectedCourseId))
        {
            _effectiveCourseId = PreselectedCourseId;
            Enrollment.CourseId = PreselectedCourseId;
        }
    }

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(Enrollment.StudentName) && !string.IsNullOrEmpty(Enrollment.CourseId))
        {
            CatalogService.SubmitEnrollmentRequest(Enrollment);
            _submitted = true;
        }
    }
}

@page "/courses"
@page "/courses/{departmentId}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services

@inject CatalogService CatalogService

<PageTitle>Courses - Lakewood University</PageTitle>

<div class="container mt-4">
    <h1>Course Catalog</h1>

    @{
        var currentDept = !string.IsNullOrEmpty(DepartmentId) ? CatalogService.GetDepartment(DepartmentId) : null;
    }
    @if (currentDept != null)
    {
        <h4 class="text-muted">@currentDept.Name</h4>
    }

    <form method="get" action="/courses" class="row g-3 my-4">
        <div class="col-md-5">
            <input type="text" name="search" class="form-control" placeholder="Search courses..." value="@Search" />
        </div>
        <div class="col-md-4">
            <select name="dept" class="form-select" onchange="this.form.action='/courses/' + this.value; this.form.submit();">
                <option value="">All Departments</option>
                @foreach (var dept in CatalogService.GetDepartments())
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <button type="submit" class="btn btn-primary w-100">Search</button>
        </div>
    </form>

    @{
        var courses = CatalogService.GetCourses(DepartmentId, Search);
        var departments = CatalogService.GetDepartments();
    }

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in courses)
                    {
                        var deptName = departments.FirstOrDefault(d => d.Id == course.DepartmentId)?.Name ?? "";
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@deptName</td>
                            <td>@course.Credits</td>
                            <td>@course.Schedule</td>
                            <td><a href="/courses/detail/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    <a href="/courses" class="btn btn-secondary mt-3">Clear Filters</a>
</div>

@code {
    [Parameter]
    public string? DepartmentId { get; set; }

    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }
}

